import{_ as o,o as a,c as n,a2 as t}from"./chunks/framework.D5wUhsuj.js";const g=JSON.parse('{"title":"Debugging","description":"","frontmatter":{},"headers":[],"relativePath":"development/04-debugging.md","filePath":"development/04-debugging.md"}'),i={name:"development/04-debugging.md"};function r(d,e,l,p,c,s){return a(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h1><p>Nejčastější problémy během hybridního vývoje:</p><ul><li><strong>Bílá obrazovka po startu:</strong> Vite build neproběhl správně, nebo Capacitor nenachází složku <code>dist</code>.</li><li><strong>Chyba sítě (Network Error):</strong> Frontend se snaží připojit na <code>localhost</code> místo na AWS server (<code>13.49.77.58</code>), nebo naopak.</li><li><strong>CORS chyby:</strong> AWS backend odmítá požadavky z Capacitor WebView (vyžaduje úpravu hlaviček na backendu).</li><li><strong>Gradle cache / OOM chyby:</strong> Termux nemá dostatek paměti pro kompilaci. Řešením je přidání <code>--no-daemon</code> k příkazu gradlew.</li><li><strong>Zastaralé UI v aplikaci:</strong> Zapomněl jsi spustit <code>npx cap sync android</code> po provedení <code>npm run build</code>.</li></ul><h2 id="doporuceny-postup-reseni" tabindex="-1">Doporučený postup řešení: <a class="header-anchor" href="#doporuceny-postup-reseni" aria-label="Permalink to &quot;Doporučený postup řešení:&quot;">​</a></h2><ol><li>Ověřit, že běží backend (např. přes curl na <code>http://13.49.77.58:3000/api/balance</code>).</li><li>Provést čistý build (<code>npm run build</code>).</li><li>Sledovat nativní logy pomocí ADB: <code>adb logcat | grep -i &quot;capacitor&quot;</code></li></ol>',5)])])}const b=o(i,[["render",r]]);export{g as __pageData,b as default};
